import axios from "axios";

const API_BASE_URL = process.env.REACT_APP_API_URL || "http://localhost:5000/api";

const apiClient = axios.create({
  baseURL: API_BASE_URL,
});

apiClient.interceptors.request.use((config) => {
  const token = localStorage.getItem("kirana_token");
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

export const loginAdmin = (payload) => apiClient.post("/auth/login", payload);
export const registerAdmin = (payload) => apiClient.post("/auth/register", payload);
export const getProfile = () => apiClient.get("/auth/me");

export const getDashboardSummary = () => apiClient.get("/dashboard/summary");

export const getProducts = (search = "") => apiClient.get("/products", { params: { search } });
export const addProduct = (formData) =>
  apiClient.post("/products", formData, {
    headers: { "Content-Type": "multipart/form-data" },
  });
export const updateProduct = (id, formData) =>
  apiClient.put(`/products/${id}`, formData, {
    headers: { "Content-Type": "multipart/form-data" },
  });
export const deleteProduct = (id) => apiClient.delete(`/products/${id}`);

export const getCustomers = (phone = "") => apiClient.get("/customers", { params: { phone } });
export const addCustomer = (payload) => apiClient.post("/customers", payload);
export const updateCustomer = (id, payload) => apiClient.put(`/customers/${id}`, payload);
export const getCustomerHistory = (id) => apiClient.get(`/customers/${id}/history`);

export const createInvoice = (payload) => apiClient.post("/invoices", payload);
export const getInvoices = (date = "") => apiClient.get("/invoices", { params: { date } });
export const downloadInvoicePdf = (id) =>
  apiClient.get(`/invoices/${id}/pdf`, { responseType: "blob" });

export const getReceipts = () => apiClient.get("/receipts");
export const downloadReceiptPdf = (id) =>
  apiClient.get(`/receipts/${id}/pdf`, { responseType: "blob" });

export const getDailySales = () => apiClient.get("/reports/daily-sales");
export const getMonthlySales = () => apiClient.get("/reports/monthly-sales");
export const getTopProducts = () => apiClient.get("/reports/top-products");

export default apiClient;
